import{_ as e,o as l,c as d,ag as a}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"Built-in Items and Prelude","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/builtins.md","filePath":"archive/reference/builtins.md"}'),o={name:"archive/reference/builtins.md"};function i(r,t,n,c,s,g){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="built-in-items-and-prelude" tabindex="-1">Built-in Items and Prelude <a class="header-anchor" href="#built-in-items-and-prelude" aria-label="Permalink to &quot;Built-in Items and Prelude&quot;">​</a></h1><p><strong>Core Language Specification</strong><br><strong>Version:</strong> 0.2.0<br><strong>Status:</strong> ✅ Implemented</p><p>This document lists all types, functions, and items automatically available in every Vex program (Prelude).</p><hr><h2 id="_1-core-types-prelude" tabindex="-1">1. Core Types (Prelude) <a class="header-anchor" href="#_1-core-types-prelude" aria-label="Permalink to &quot;1. Core Types (Prelude)&quot;">​</a></h2><p>These types are available without import.</p><h3 id="primitive-types" tabindex="-1">Primitive Types <a class="header-anchor" href="#primitive-types" aria-label="Permalink to &quot;Primitive Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>i8</code>, <code>i16</code>, <code>i32</code>, <code>i64</code></td><td style="text-align:left;">Signed Integers</td></tr><tr><td style="text-align:left;"><code>u8</code>, <code>u16</code>, <code>u32</code>, <code>u64</code></td><td style="text-align:left;">Unsigned Integers</td></tr><tr><td style="text-align:left;"><code>f32</code>, <code>f64</code></td><td style="text-align:left;">Floating Point</td></tr><tr><td style="text-align:left;"><code>bool</code></td><td style="text-align:left;">Boolean (true/false)</td></tr><tr><td style="text-align:left;"><code>string</code></td><td style="text-align:left;">UTF-8 String</td></tr><tr><td style="text-align:left;"><code>void</code></td><td style="text-align:left;">Empty type (Unit)</td></tr></tbody></table><h3 id="composite-types" tabindex="-1">Composite Types <a class="header-anchor" href="#composite-types" aria-label="Permalink to &quot;Composite Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>Option&lt;T&gt;</code></td><td style="text-align:left;">Optional value (Some/None)</td></tr><tr><td style="text-align:left;"><code>Result&lt;T,E&gt;</code></td><td style="text-align:left;">Success/Failure (Ok/Err)</td></tr><tr><td style="text-align:left;"><code>Vec&lt;T&gt;</code></td><td style="text-align:left;">Dynamic array</td></tr><tr><td style="text-align:left;"><code>Map&lt;K,V&gt;</code></td><td style="text-align:left;">Hash map</td></tr><tr><td style="text-align:left;"><code>Box&lt;T&gt;</code></td><td style="text-align:left;">Heap allocation</td></tr></tbody></table><hr><h2 id="_2-built-in-functions" tabindex="-1">2. Built-in Functions <a class="header-anchor" href="#_2-built-in-functions" aria-label="Permalink to &quot;2. Built-in Functions&quot;">​</a></h2><p>Functions available globally. All built-in functions are prefixed with <code>$</code>.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Function</th><th style="text-align:left;">Signature</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>$print</code></td><td style="text-align:left;"><code>fn(any...)</code></td><td style="text-align:left;">Print to stdout</td></tr><tr><td style="text-align:left;"><code>$println</code></td><td style="text-align:left;"><code>fn(any...)</code></td><td style="text-align:left;">Print line to stdout</td></tr><tr><td style="text-align:left;"><code>$panic</code></td><td style="text-align:left;"><code>fn(string) -&gt; !</code></td><td style="text-align:left;">Terminate program</td></tr><tr><td style="text-align:left;"><code>$assert</code></td><td style="text-align:left;"><code>fn(bool)</code></td><td style="text-align:left;">Verify condition</td></tr><tr><td style="text-align:left;"><code>$sizeof</code></td><td style="text-align:left;"><code>fn&lt;T&gt;() -&gt; usize</code></td><td style="text-align:left;">Get type size</td></tr><tr><td style="text-align:left;"><code>$len</code></td><td style="text-align:left;"><code>fn&lt;T&gt;(T) -&gt; u64</code></td><td style="text-align:left;">Get length</td></tr><tr><td style="text-align:left;"><code>$cap</code></td><td style="text-align:left;"><code>fn&lt;T&gt;(T) -&gt; u64</code></td><td style="text-align:left;">Get capacity</td></tr></tbody></table><hr><h2 id="_3-operators" tabindex="-1">3. Operators <a class="header-anchor" href="#_3-operators" aria-label="Permalink to &quot;3. Operators&quot;">​</a></h2><p>Standard operators supported by the language.</p><h3 id="arithmetic" tabindex="-1">Arithmetic <a class="header-anchor" href="#arithmetic" aria-label="Permalink to &quot;Arithmetic&quot;">​</a></h3><p><code>+</code>, <code>-</code>, <code>*</code>, <code>/</code>, <code>%</code></p><h3 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h3><p><code>==</code>, <code>!=</code>, <code>&lt;</code>, <code>&gt;</code>, <code>&lt;=</code>, <code>&gt;=</code></p><h3 id="logical" tabindex="-1">Logical <a class="header-anchor" href="#logical" aria-label="Permalink to &quot;Logical&quot;">​</a></h3><p><code>&amp;&amp;</code>, <code>||</code>, <code>!</code></p><h3 id="bitwise" tabindex="-1">Bitwise <a class="header-anchor" href="#bitwise" aria-label="Permalink to &quot;Bitwise&quot;">​</a></h3><p><code>&amp;</code>, <code>|</code>, <code>^</code>, <code>&lt;&lt;</code>, <code>&gt;&gt;</code>, <code>~</code></p><h3 id="advanced" tabindex="-1">Advanced <a class="header-anchor" href="#advanced" aria-label="Permalink to &quot;Advanced&quot;">​</a></h3><ul><li><code>!&gt;</code>: Error Rescue</li><li><code>?</code>: Error Propagation</li><li><code>??</code>: Null Coalescing (Option)</li></ul><hr><h2 id="_4-contracts-prelude" tabindex="-1">4. Contracts (Prelude) <a class="header-anchor" href="#_4-contracts-prelude" aria-label="Permalink to &quot;4. Contracts (Prelude)&quot;">​</a></h2><p>All system contracts are prefixed with <code>$</code>.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Contract</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>$Drop</code></td><td style="text-align:left;">Destructor capability</td></tr><tr><td style="text-align:left;"><code>$Clone</code></td><td style="text-align:left;">Copy capability</td></tr><tr><td style="text-align:left;"><code>$Error</code></td><td style="text-align:left;">Error reporting</td></tr><tr><td style="text-align:left;"><code>$Display</code></td><td style="text-align:left;">String formatting</td></tr><tr><td style="text-align:left;"><code>$Default</code></td><td style="text-align:left;">Default value creation</td></tr></tbody></table>',31)])])}const p=e(o,[["render",i]]);export{h as __pageData,p as default};
